const ALLOWED_STATUSES = new Set(['in_review', 'approved', 'published']);

function prop(page, name) {
  return page.properties?.[name];
}

function richTextToPlain(parts = []) {
  return parts.map((p) => p.plain_text || p.text?.content || '').join('').trim();
}

function propertyText(page, name) {
  const p = prop(page, name);
  if (!p) return '';
  if (p.type === 'title') return richTextToPlain(p.title || []);
  if (p.type === 'rich_text') return richTextToPlain(p.rich_text || []);
  if (p.type === 'select') return p.select?.name || '';
  if (p.type === 'status') return p.status?.name || '';
  if (p.type === 'formula') return p.formula?.string || String(p.formula?.number || '');
  return '';
}

function propertyMulti(page, name) {
  const p = prop(page, name);
  if (!p) return [];
  if (p.type === 'multi_select') return (p.multi_select || []).map((x) => x.name).filter(Boolean);
  if (p.type === 'people') return (p.people || []).map((x) => x.name || x.id).filter(Boolean);
  return [];
}

const root = $input.first()?.json || {};
const results = root.results || root.body?.results || [];

return results
  .map((page) => {
    const docId = propertyText(page, 'Doc ID') || page.id;
    const status = propertyText(page, 'Status');

    return {
      json: {
        page_id: page.id,
        doc_id: docId,
        title: docId,
        status,
        module: propertyText(page, 'Module'),
        type: propertyText(page, 'Type'),
        authority: propertyText(page, 'Authority'),
        topic_tags: propertyMulti(page, 'Topic Tags'),
        reviewer: propertyMulti(page, 'Reviewer'),
        source_url: page.url || '',
        updated_at: page.last_edited_time || new Date().toISOString()
      }
    };
  })
  .filter((item) => ALLOWED_STATUSES.has(item.json.status));

function richTextToMarkdown(parts = []) {
  return parts.map((part) => {
    const text = part.plain_text || part.text?.content || '';
    const href = part.href || part.text?.link?.url;
    let out = text;

    if (part.annotations?.code) out = '`' + out + '`';
    if (part.annotations?.bold) out = '**' + out + '**';
    if (part.annotations?.italic) out = '*' + out + '*';
    if (href) out = '[' + out + '](' + href + ')';

    return out;
  }).join('');
}

function blockToMarkdown(block, depth = 0) {
  const type = block.type;
  const data = block[type] || {};
  const text = richTextToMarkdown(data.rich_text || []);
  const indent = '  '.repeat(depth);
  let line = '';

  switch (type) {
    case 'paragraph':
      line = text;
      break;
    case 'heading_1':
      line = '# ' + text;
      break;
    case 'heading_2':
      line = '## ' + text;
      break;
    case 'heading_3':
      line = '### ' + text;
      break;
    case 'bulleted_list_item':
      line = indent + '- ' + text;
      break;
    case 'numbered_list_item':
      line = indent + '1. ' + text;
      break;
    case 'to_do':
      line = indent + '- [' + (data.checked ? 'x' : ' ') + '] ' + text;
      break;
    case 'toggle':
      line = text ? indent + '<details><summary>' + text + '</summary>' : '';
      break;
    case 'quote':
    case 'callout':
      line = text ? '> ' + text : '';
      break;
    case 'code':
      line = '```' + (data.language || '') + '\n' + text + '\n```';
      break;
    case 'divider':
      line = '---';
      break;
    case 'table_row':
      line = '| ' + (data.cells || []).map((cell) => richTextToMarkdown(cell)).join(' | ') + ' |';
      break;
    case 'image':
      line = '[Image: ' + (data.caption ? richTextToMarkdown(data.caption) : data.file?.url || data.external?.url || 'Notion image') + ']';
      break;
    case 'bookmark':
    case 'embed':
    case 'link_preview':
      line = data.url ? '[' + type + ': ' + data.url + ']' : '';
      break;
    case 'child_page':
      line = '## ' + (data.title || 'Child page');
      break;
    default:
      line = text;
  }

  return line;
}

const rows = $('Code - Normalize Notion Rows').all();

return $input.all().map((item, index) => {
  const row = rows[index]?.json || {};
  const blocks = item.json.results || item.json.body?.results || [];
  const content = blocks
    .map((block) => blockToMarkdown(block))
    .filter(Boolean)
    .join('\n\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();

  return {
    json: {
      doc_id: row.doc_id,
      title: row.title || row.doc_id,
      status: row.status,
      module: row.module,
      type: row.type,
      authority: row.authority,
      topic_tags: row.topic_tags || [],
      source_url: row.source_url,
      content,
      updated_at: row.updated_at
    }
  };
});

function safeFilename(input) {
  return String(input || 'untitled')
    .normalize('NFKD')
    .replace(/[<>:"/\\|?*\x00-\x1F]/g, '_')
    .replace(/\s+/g, '_')
    .replace(/_+/g, '_')
    .replace(/^\.+/, '')
    .replace(/\.+$/, '')
    .slice(0, 120) || 'untitled';
}

function toBase64(text) {
  return Buffer.from(text, 'utf8').toString('base64');
}

const chunks = $input.all().map((item) => item.json);
const used = new Map();
const commitMessage = `kb sync: Notion KB ${new Date().toISOString()}`;

const files = chunks.map((chunk) => {
  const base = safeFilename(chunk.doc_id);
  const count = used.get(base) || 0;
  used.set(base, count + 1);

  const filename = count === 0 ? `${base}.json` : `${base}_${count + 1}.json`;
  const path = `KB/${filename}`;
  const jsonText = JSON.stringify(chunk, null, 2) + '\n';

  return {
    json: {
      is_index: false,
      doc_id: chunk.doc_id,
      path,
      json_text: jsonText,
      content_base64: toBase64(jsonText),
      commit_message: commitMessage
    }
  };
});

const index = {
  source: 'notion',
  source_data_source_id: 'c52dad9d-1fa0-45af-a23b-68785536a494',
  status_filter: ['in_review', 'approved', 'published'],
  production_note: 'Before real rollout, tighten status_filter to published only.',
  count: chunks.length,
  updated_at: chunks.map((chunk) => chunk.updated_at).sort().at(-1) || null,
  docs: files.map((fileItem, index) => {
    const chunk = chunks[index];
    return {
      doc_id: chunk.doc_id,
      title: chunk.title,
      status: chunk.status,
      module: chunk.module,
      type: chunk.type,
      authority: chunk.authority,
      topic_tags: chunk.topic_tags || [],
      path: fileItem.json.path,
      source_url: chunk.source_url,
      updated_at: chunk.updated_at
    };
  })
};

const indexText = JSON.stringify(index, null, 2) + '\n';

files.push({
  json: {
    is_index: true,
    doc_id: '_index',
    path: 'KB/_index.json',
    json_text: indexText,
    content_base64: toBase64(indexText),
    commit_message: commitMessage
  }
});

return files;

function stripBase64Whitespace(value) {
  return String(value || '').replace(/\s/g, '');
}

const payloads = $('Code - Build GitHub File Payloads').all();
const responses = $input.all();

return payloads.map((payloadItem, index) => {
  const file = payloadItem.json;
  const response = responses[index]?.json || {};
  const statusCode = response.statusCode || response.response?.statusCode;
  const body = response.body || response;
  const existingSha = body.sha || null;
  const existingContent = stripBase64Whitespace(body.content);
  const desiredContent = stripBase64Whitespace(file.content_base64);

  let action = 'create';
  if (statusCode === 404 || body.message === 'Not Found') {
    action = 'create';
  } else if (existingSha && existingContent === desiredContent) {
    action = 'skip';
  } else if (existingSha) {
    action = 'update';
  }

  const githubBody = {
    message: file.commit_message,
    content: file.content_base64
  };

  if (action === 'update') {
    githubBody.sha = existingSha;
  }

  return {
    json: {
      ...file,
      action,
      http_method: action === 'skip' ? 'GET' : 'PUT',
      github_body: action === 'skip' ? {} : githubBody,
      http_body: action === 'skip' ? '{}' : JSON.stringify(githubBody),
      sha: existingSha
    }
  };
});

const files = $('Code - Diff GitHub Files').all().map((item) => item.json);

return [
  {
    json: {
      has_writes: files.some((file) => file.action !== 'skip')
    }
  }
];

const files = $('Code - Diff GitHub Files').all().map((item) => item.json);
const responsesByPath = new Map(
  $input.all().map((item) => {
    const response = item.json;
    const path = response.body?.content?.path || response.body?.path || response.path;
    return [path, response];
  })
);
const docs = files.filter((file) => !file.is_index);
const first = files[0] || {};

function isSuccessStatus(statusCode) {
  return statusCode >= 200 && statusCode < 300;
}

const results = files.map((file) => {
  const response = file.action === 'skip'
    ? {}
    : responsesByPath.get(file.path) || {};
  const statusCode = response.statusCode || response.response?.statusCode || response.body?.status;
  const skipped = file.action === 'skip';
  const success = skipped || isSuccessStatus(statusCode);

  return {
    path: file.path,
    action: file.action,
    status_code: statusCode || null,
    success,
    error: success ? null : response.body?.message || response.message || 'GitHub write failed'
  };
});

const docResults = results.filter((file) => file.path !== 'KB/_index.json');
const failures = results.filter((file) => !file.success);

return [
  {
    json: {
      ok: failures.length === 0,
      synced: docResults.filter((file) => file.success).length,
      created: docResults.filter((file) => file.success && file.action === 'create').length,
      updated: docResults.filter((file) => file.success && file.action === 'update').length,
      skipped: docs.filter((file) => file.action === 'skip').length,
      failed: failures.length,
      commit_message: first.commit_message || '',
      index_path: 'KB/_index.json',
      errors: failures.slice(0, 10)
    }
  }
];
